+        },
+      }),
+    ).toMatchObject(MODEL);
+
+    await prepareProviderDynamicModel({
+      provider: "demo",
+      context: {
+        provider: "demo",
+        modelId: MODEL.id,
+        modelRegistry: { find: () => null } as never,
+      },
+    });
+
+    expect(
+      resolveProviderCapabilitiesWithPlugin({
+        provider: "demo",
+      }),
