+    ).toMatchObject({
+      temperature: 0.3,
+      transport: "auto",
+    });
+
+    expect(
+      wrapProviderStreamFn({
+        provider: "demo",
+        context: {
+          provider: "demo",
+          modelId: MODEL.id,
+          streamFn: vi.fn(),
+        },
+      }),
+    ).toBeTypeOf("function");
+
+    expect(
+      normalizeProviderResolvedModelWithPlugin({
+        provider: "demo",
+        context: {
+          provider: "demo",
+          modelId: MODEL.id,
+          model: MODEL,
+        },
+      }),
